// Get data from previous nodes
const customer = $input.item.json;
const order = $('New Order').item.json.body;

// Simulate order count using customer ID
// In real Shopify this would be customer.orders_count
const orderCount = customer.id % 10; // gives us 0-9 for simulation

// Calculate loyalty tier
let tier;
let tierLabel;

if (orderCount <= 1) {
  tier = 'first_timer';
  tierLabel = 'First Timer';
} else if (orderCount <= 4) {
  tier = 'returning';
  tierLabel = 'Returning Customer';
} else {
  tier = 'vip';
  tierLabel = 'VIP Customer';
}

// Return everything the next nodes need
return {
  // Customer info
  firstName: customer.firstName,
  lastName: customer.lastName,
  email: customer.email,

  // Order info
  orderId: order.orderId,
  product: order.product,
  amount: order.amount,

  // Tier decision
  tier: tier,
  tierLabel: tierLabel,
  orderCount: orderCount,

  // Discount logic
  discountCode: tier === 'vip' ? 'VIP20' : tier === 'returning' ? 'RETURN10' : 'WELCOME5'
};
